// 교육용 빅뱅 시뮬레이션 - 중앙 뭉치 + 주변 궤도 형식
import * as THREE from "three";

/**
 * 1️⃣ 쿼크-글루온 플라즈마 (2초)
 * 중앙에 뜨거운 입자 뭉치 + 주변 3개 궤도
 */
export function createQuarkGluonPlasma(stageProgress = 0) {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // ========== 중앙 핵 뭉치 ==========
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 100000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    // 중앙에 밀집된 구체
    const r = Math.pow(Math.random(), 0.33) * 40;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 컬러풀한 색상 - 빨강/파랑/초록/노랑
    const colorType = Math.floor(Math.random() * 4);
    if (colorType === 0) { // 빨강
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 0.3;
      coreColors[i * 3 + 2] = 0.3;
    } else if (colorType === 1) { // 파랑
      coreColors[i * 3] = 0.3;
      coreColors[i * 3 + 1] = 0.5;
      coreColors[i * 3 + 2] = 1.0;
    } else if (colorType === 2) { // 초록
      coreColors[i * 3] = 0.3;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 0.3;
    } else { // 노랑
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 0.3;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.8
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  corePoints.userData.isDynamic = true;
  group.add(corePoints);

  // ========== 주변 3개 궤도 ==========
  const orbits = [
    { radius: 150, color: [1.0, 0.3, 0.3], count: 120000 },
    { radius: 250, color: [0.3, 0.5, 1.0], count: 120000 },
    { radius: 350, color: [0.3, 1.0, 0.3], count: 120000 }
  ];

  orbits.forEach((orbit, orbitIdx) => {
    const orbitGeometry = new THREE.BufferGeometry();
    const positions = new Float32Array(orbit.count * 3);
    const colors = new Float32Array(orbit.count * 3);

    for (let i = 0; i < orbit.count; i++) {
      const baseAngle = (i / orbit.count) * Math.PI * 2;
      const angle = baseAngle + time * (orbitIdx + 0.5);
      const tiltAngle = (orbitIdx / 3) * Math.PI * 0.3;

      const x = Math.cos(angle) * orbit.radius;
      const y = Math.sin(angle) * orbit.radius * Math.cos(tiltAngle);
      const z = Math.sin(angle) * orbit.radius * Math.sin(tiltAngle);

      positions[i * 3] = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = z;

      colors[i * 3] = orbit.color[0];
      colors[i * 3 + 1] = orbit.color[1];
      colors[i * 3 + 2] = orbit.color[2];
    }

    orbitGeometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    orbitGeometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const orbitMaterial = new THREE.PointsMaterial({
      size: 1.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.7
    });

    const orbitPoints = new THREE.Points(orbitGeometry, orbitMaterial);
    orbitPoints.userData.isDynamic = true;
    group.add(orbitPoints);
  });

  return group;
}

/**
 * 2️⃣ 쿼크 결합 (2.5초)
 * 궤도 입자들이 중앙으로 모이면서 핵 형성 시작
 */
export function createQuarkCombination(stageProgress = 0) {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // ========== 성장하는 중앙 핵 ==========
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 150000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  // 핵의 크기가 진행도에 따라 증가
  const coreRadius = 40 + stageProgress * 40;

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * coreRadius;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵 색상: 주로 빨강(양성자) + 파랑(중성자)
    if (Math.random() > 0.4) {
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 0.3;
      coreColors[i * 3 + 2] = 0.3;
    } else {
      coreColors[i * 3] = 0.3;
      coreColors[i * 3 + 1] = 0.5;
      coreColors[i * 3 + 2] = 1.0;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5 + stageProgress * 0.4
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  corePoints.userData.isDynamic = true;
  group.add(corePoints);

  // ========== 수축하는 3개 궤도 ==========
  const orbits = [
    { startRadius: 150, color: [1.0, 0.3, 0.3], count: 100000 },
    { startRadius: 250, color: [0.3, 0.5, 1.0], count: 100000 },
    { startRadius: 350, color: [0.3, 1.0, 0.3], count: 100000 }
  ];

  orbits.forEach((orbit, orbitIdx) => {
    const orbitGeometry = new THREE.BufferGeometry();
    const positions = new Float32Array(orbit.count * 3);
    const colors = new Float32Array(orbit.count * 3);

    // 진행도에 따라 궤도 반경이 감소
    const radius = orbit.startRadius * (1 - stageProgress) + 100 * stageProgress;

    for (let i = 0; i < orbit.count; i++) {
      const baseAngle = (i / orbit.count) * Math.PI * 2;
      const angle = baseAngle + time * (orbitIdx + 0.5);
      const tiltAngle = (orbitIdx / 3) * Math.PI * 0.3;

      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius * Math.cos(tiltAngle);
      const z = Math.sin(angle) * radius * Math.sin(tiltAngle);

      positions[i * 3] = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = z;

      colors[i * 3] = orbit.color[0];
      colors[i * 3 + 1] = orbit.color[1];
      colors[i * 3 + 2] = orbit.color[2];
    }

    orbitGeometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    orbitGeometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const orbitMaterial = new THREE.PointsMaterial({
      size: 1.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: (1 - stageProgress * 0.3) * 0.7
    });

    const orbitPoints = new THREE.Points(orbitGeometry, orbitMaterial);
    orbitPoints.userData.isDynamic = true;
    group.add(orbitPoints);
  });

  return group;
}

/**
 * 3️⃣ 핵융합 - 원자핵 형성 (2.5초)
 * 양성자/중성자들이 핵으로 모이기 시작, 헬륨-4 등 경핵 형성
 */
export function createNucleosynthesis(stageProgress = 0) {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // ========== 형성되는 원자핵 ==========
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 200000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  const coreRadius = 40 + stageProgress * 50;

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * coreRadius;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵 색상: 청록색(He-4), 녹색(Li), 노랑(Be)
    const colorType = Math.floor(Math.random() * 3);
    if (colorType === 0) { // He-4 - 청록
      coreColors[i * 3] = 0.2;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 1.0;
    } else if (colorType === 1) { // Li - 녹색
      coreColors[i * 3] = 0.3;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 0.3;
    } else { // Be - 노랑
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 0.3;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.6 + stageProgress * 0.3
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  corePoints.userData.isDynamic = true;
  group.add(corePoints);

  // ========== 4개 PN 궤도 ==========
  const orbits = [
    { startRadius: 150, color: [1.0, 0.5, 0.5], count: 80000 },
    { startRadius: 250, color: [0.5, 0.7, 1.0], count: 80000 },
    { startRadius: 350, color: [0.5, 1.0, 0.5], count: 80000 },
    { startRadius: 450, color: [1.0, 1.0, 0.5], count: 80000 }
  ];

  orbits.forEach((orbit, orbitIdx) => {
    const orbitGeometry = new THREE.BufferGeometry();
    const positions = new Float32Array(orbit.count * 3);
    const colors = new Float32Array(orbit.count * 3);

    const radius = orbit.startRadius * (1 - stageProgress) + 120 * stageProgress;

    for (let i = 0; i < orbit.count; i++) {
      const baseAngle = (i / orbit.count) * Math.PI * 2;
      const angle = baseAngle + time * (orbitIdx + 0.5);
      const tiltAngle = (orbitIdx / 4) * Math.PI * 0.4;

      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius * Math.cos(tiltAngle);
      const z = Math.sin(angle) * radius * Math.sin(tiltAngle);

      positions[i * 3] = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = z;

      colors[i * 3] = orbit.color[0];
      colors[i * 3 + 1] = orbit.color[1];
      colors[i * 3 + 2] = orbit.color[2];
    }

    orbitGeometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    orbitGeometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const orbitMaterial = new THREE.PointsMaterial({
      size: 1.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: (1 - stageProgress * 0.2) * 0.7
    });

    const orbitPoints = new THREE.Points(orbitGeometry, orbitMaterial);
    orbitPoints.userData.isDynamic = true;
    group.add(orbitPoints);
  });

  return group;
}

/**
 * 4️⃣ 원자 형성 (3초)
 * 작은 원자핵 주변을 전자 껍질이 감싸는 보어 모델
 */
export function createAtomFormation(stageProgress = 0) {
  const group = new THREE.Group();
  const time = Date.now() * 0.001;

  // ========== 작은 원자핵 (중앙) ==========
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 100000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  // 핵은 매우 작음
  const coreRadius = 8;

  for (let i = 0; i < numCore; i++) {
    const r = Math.pow(Math.random(), 0.33) * coreRadius;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵은 노랑
    coreColors[i * 3] = 1.0;
    coreColors[i * 3 + 1] = 1.0;
    coreColors[i * 3 + 2] = 0.3;
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 3.0 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.8 + stageProgress * 0.2
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // ========== 3개 전자 껍질 (K, L, M) ==========
  const shells = [
    { radius: 80, color: [0.2, 0.8, 1.0], count: 150000 },   // K-shell
    { radius: 160, color: [0.5, 0.9, 1.0], count: 150000 },  // L-shell
    { radius: 240, color: [0.7, 0.95, 1.0], count: 100000 }  // M-shell
  ];

  shells.forEach((shell, shellIdx) => {
    const shellGeometry = new THREE.BufferGeometry();
    const positions = new Float32Array(shell.count * 3);
    const colors = new Float32Array(shell.count * 3);

    // 진행도에 따라 전자 껍질 크기 증가
    const radius = shell.radius * stageProgress;

    for (let i = 0; i < shell.count; i++) {
      // 기본 각도 (고정)
      const baseAngle = (i / shell.count) * Math.PI * 2;

      // 시간에 따라 회전 - 각 껍질마다 다른 속도
      const angle = baseAngle + time * (shellIdx + 1) * 0.5;

      // 각 껍질별 궤도 평면 틸트
      const tiltAngle = (i / shell.count) * Math.PI * 0.4;

      const x = Math.cos(angle) * radius;
      const y = Math.sin(angle) * radius * Math.cos(tiltAngle);
      const z = Math.sin(angle) * radius * Math.sin(tiltAngle);

      positions[i * 3] = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = z;

      colors[i * 3] = shell.color[0];
      colors[i * 3 + 1] = shell.color[1];
      colors[i * 3 + 2] = shell.color[2];
    }

    shellGeometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    shellGeometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const shellMaterial = new THREE.PointsMaterial({
      size: 1.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.1 + stageProgress * 0.6
    });

    const shellPoints = new THREE.Points(shellGeometry, shellMaterial);
    shellPoints.userData.isDynamic = true;
    group.add(shellPoints);
  });

  return group;
}


// ========== 단계 정보 ==========
export const educationalBigBangStages = [
  {
    id: 0,
    name: "쿼크-글루온 플라즈마",
    timeRange: "10⁻¹² 초",
    temperature: "10¹⁶ K",
    description: "우주 초기 - 극도로 뜨거운 쿼크와 글루온의 혼합",
    duration: 2000
  },
  {
    id: 1,
    name: "쿼크 → 양성자/중성자",
    timeRange: "10⁻⁶ 초",
    temperature: "10¹³ K",
    description: "쿼크들이 결합하여 양성자와 중성자 형성",
    duration: 2500
  },
  {
    id: 2,
    name: "핵융합 → 원자핵 형성",
    timeRange: "1-3 분",
    temperature: "10⁹ K",
    description: "양성자/중성자가 핵융합하여 헬륨-4, 리튬, 베릴륨 등 경핵 형성",
    duration: 2500
  },
  {
    id: 3,
    name: "원자 형성 (보어 모델)",
    timeRange: "38만 년",
    temperature: "< 10⁴ K",
    description: "전자가 원자핵 주변의 껍질에 캡처되어 중성 원자 형성",
    duration: 3000
  }
];

// 현재 단계 선택
export const getStageFunction = (stageId) => {
  const functions = [
    createQuarkGluonPlasma,
    createQuarkCombination,
    createNucleosynthesis,
    createAtomFormation
  ];
  return functions[stageId] || createQuarkGluonPlasma;
};
